29	function validUkPostcodeInput(value: unknown): value is string {
30	  if (typeof value !== "string") return false;
31	  const cleaned = value.trim().toUpperCase();
32	  return /^[A-Z]{1,2}\d[A-Z\d]?\s*\d?[A-Z]{0,2}$/.test(cleaned) && cleaned.length >= 2;
33	}
