47	          name: "Priority Booking Deposit",
48	          description: "Fully deductible against the final invoice.",
49	        },
50	        unit_amount: safeAmount,
51	      },
52	      quantity: 1,
53	    }],
54	    mode: "payment",
55	    success_url: `${origin || DEFAULT_ORIGIN}/dashboard?payment=success`,
56	    cancel_url: `${origin || DEFAULT_ORIGIN}/dashboard?payment=cancelled`,
57	    metadata: { tradie_id: tradieId },
58	  });
