63	const rateLimitMap = new Map<string, { count: number; resetAt: number }>();
64	const RATE_LIMIT = 200; // TEST MODE — revert to 10 before launch
65	const RATE_WINDOW_MS = 60_000;
66	
67	function checkRateLimit(ip: string): boolean {
68	  const now = Date.now();
69	  const entry = rateLimitMap.get(ip);
70	  if (!entry || now > entry.resetAt) {
71	    rateLimitMap.set(ip, { count: 1, resetAt: now + RATE_WINDOW_MS });
72	    return true;
73	  }
74	  if (entry.count >= RATE_LIMIT) return false;
75	  entry.count++;
76	  return true;
77	}
