268	async function startServer() {
269	  warnIfMissingReleaseEnv();
270	
271	  const app = express();
272	  app.use(express.json());
273	  registerApi(app);
274	
275	  if (process.env.NODE_ENV !== "production") {
276	    const vite = await createViteServer({ server: { middlewareMode: true }, appType: "spa" });
277	    app.use(vite.middlewares);
278	  } else {
279	    const distPath = path.join(process.cwd(), "dist");
280	    app.use(express.static(distPath));
281	    app.get("*", (_req, res) => res.sendFile(path.join(distPath, "index.html")));
282	  }
283	
284	  const port = Number(process.env.PORT || 3000);
285	  app.listen(port, "0.0.0.0", () => console.log(`JobFilter running on http://localhost:${port}`));
286	}
287	
288	startServer().catch((error) => {
289	  console.error("Server failed:", error);
290	  process.exit(1);
